@dataclass(repr=False)
class ProxyServer(ComputerNetworkNode):
    """
    In computer networking, a proxy server is a server application or appliance that acts as an intermediary for
    requests from clients seeking resources from servers that provide those resources. A proxy server thus functions
    on behalf of the client when requesting service, potentially masking the true origin of the request to the
    resource server.
    """
    _inherited_slots: ClassVar[list[str]] = []

    class_class_uri: ClassVar[URIRef] = D3F["ProxyServer"]
    class_class_curie: ClassVar[str] = "d3f:ProxyServer"
    class_name: ClassVar[str] = "ProxyServer"
    class_model_uri: ClassVar[URIRef] = D3F.ProxyServer

    input_of: Optional[Union[Union[dict, Event], list[Union[dict, Event]]]] = empty_list()
    may_have_weakness: Optional[Union[Union[dict, "Weakness"], list[Union[dict, "Weakness"]]]] = empty_list()
    output_of: Optional[Union[Union[dict, Event], list[Union[dict, Event]]]] = empty_list()
    d3fend_artifact_data_property: Optional[str] = None

    def __post_init__(self, *_: str, **kwargs: Any):
        if not isinstance(self.input_of, list):
            self.input_of = [self.input_of] if self.input_of is not None else []
        self.input_of = [v if isinstance(v, Event) else Event(**as_dict(v)) for v in self.input_of]

        if not isinstance(self.may_have_weakness, list):
            self.may_have_weakness = [self.may_have_weakness] if self.may_have_weakness is not None else []
        self.may_have_weakness = [v if isinstance(v, Weakness) else Weakness(**as_dict(v)) for v in self.may_have_weakness]

        if not isinstance(self.output_of, list):
            self.output_of = [self.output_of] if self.output_of is not None else []
        self.output_of = [v if isinstance(v, Event) else Event(**as_dict(v)) for v in self.output_of]

        if self.d3fend_artifact_data_property is not None and not isinstance(self.d3fend_artifact_data_property, str):
            self.d3fend_artifact_data_property = str(self.d3fend_artifact_data_property)

        super().__post_init__(**kwargs)


