class Session(DigitalInformationBearer):
    """
    In computer science, in particular networking, a session is a semi-permanent interactive information interchange,
    also known as a dialogue, a conversation or a meeting, between two or more communicating devices, or between a
    computer and user (see Login session). A session is set up or established at a certain point in time, and then
    torn down at some later point. An established communication session may involve more than one message in each
    direction. A session is typically, but not always, stateful, meaning that at least one of the communicating parts
    needs to save information about the session history in order to be able to communicate, as opposed to stateless
    communication, where the communication consists of independent requests with responses.
    """
    _inherited_slots: ClassVar[list[str]] = []

    class_class_uri: ClassVar[URIRef] = D3F["Session"]
    class_class_curie: ClassVar[str] = "d3f:Session"
